   148→// BindingREST implements the REST endpoint for binding pods to nodes when etcd is in use.
   149→type BindingREST struct {
   150→	store *genericregistry.Store
   151→}
   152→
   153→// NamespaceScoped fulfill rest.Scoper
   154→func (r *BindingREST) NamespaceScoped() bool {
   155→	return r.store.NamespaceScoped()
   156→}
   157→
   158→// New creates a new binding resource
   159→func (r *BindingREST) New() runtime.Object {
   160→	return &api.Binding{}
   161→}
   162→
   163→// Destroy cleans up resources on shutdown.
   164→func (r *BindingREST) Destroy() {
   165→	// Given that underlying store is shared with REST,
   166→	// we don't destroy it here explicitly.
   167→}
   168→
   169→var _ = rest.NamedCreater(&BindingREST{})
   170→var _ = rest.SubresourceObjectMetaPreserver(&BindingREST{})
   171→
   172→// Create ensures a pod is bound to a specific host.
   173→func (r *BindingREST) Create(ctx context.Context, name string, obj runtime.Object, createValidation rest.ValidateObjectFunc, options *metav1.CreateOptions) (out runtime.Object, err error) {
   174→	binding, ok := obj.(*api.Binding)
   175→	if !ok {
   176→		return nil, errors.NewBadRequest(fmt.Sprintf("not a Binding object: %#v", obj))
   177→	}
   178→
   179→	if name != binding.Name {
   180→		return nil, errors.NewBadRequest("name in URL does not match name in Binding object")
   181→	}
   182→
   183→	// TODO: move me to a binding strategy
   184→	if errs := validation.ValidatePodBinding(binding); len(errs) != 0 {
   185→		return nil, errs.ToAggregate()
   186→	}
   187→
   188→	if createValidation != nil {
   189→		if err := createValidation(ctx, binding.DeepCopyObject()); err != nil {
   190→			return nil, err
   191→		}
   192→	}
   193→
   194→	err = r.assignPod(ctx, binding.UID, binding.ResourceVersion, binding.Name, binding.Target.Name, binding.Annotations, dryrun.IsDryRun(options.DryRun))
   195→	out = &metav1.Status{Status: metav1.StatusSuccess}
   196→	return
   197→}
   198→
   199→// PreserveRequestObjectMetaSystemFieldsOnSubresourceCreate indicates to a
   200→// handler that this endpoint requires the UID and ResourceVersion to use as
   201→// preconditions. Other fields, such as timestamp, are ignored.
   202→func (r *BindingREST) PreserveRequestObjectMetaSystemFieldsOnSubresourceCreate() bool {
   203→	return true
   204→}
